parameters.jsonData:
[
    {"value": "true",  "label": "Yes — show only the most recent CollectionTime"},
    {"value": "false", "label": "No — include every run in the time range"}
]

content.query:
// KPI tiles -- filtered by the parameters above.
// A base query + a second query comparing to the previous run drive the 4 tiles.
let _Latest = toscalar(SI_RiskAnalysis_Summary_CL | where TimeGenerated {TimeRange} | summarize max(CollectionTime));
let _Prev   = toscalar(SI_RiskAnalysis_Summary_CL | where TimeGenerated {TimeRange} | where CollectionTime < _Latest | summarize max(CollectionTime));
let _Base =
    SI_RiskAnalysis_Summary_CL
    | where TimeGenerated {TimeRange}
    | where (tobool('{LatestRunOnly}') == false) or CollectionTime == _Latest
    | where SecurityDomain   in ({SecurityDomain})
    | where SecuritySeverity in ({SecuritySeverity})
    | where tostring(CriticalityTier) in ({CriticalityTier})
    | where Subcategory      in ({SubCategory})
    | where ('{SearchText}' == '') or ConfigurationName contains '{SearchText}' or TraceName contains '{SearchText}';
let _Now  = _Base | where CollectionTime == _Latest | summarize TotalRisk = sum(todouble(RiskScoreTotal)), Open = count_distinct(TraceID), Critical = count_distinctif(TraceID, SecuritySeverity in ('Critical','Very High','High'));
let _Then = SI_RiskAnalysis_Summary_CL | where TimeGenerated {TimeRange} | where CollectionTime == _Prev | summarize PrevTotal = sum(todouble(RiskScoreTotal));
_Now | extend PrevTotal = toscalar(_Then | project PrevTotal)
     | extend DeltaPct = iff(isnotnull(PrevTotal) and PrevTotal != 0, round(100.0 * (TotalRisk - PrevTotal) / PrevTotal, 1), todouble(0))
     | project
         ['Total risk score']      = TotalRisk,
         ['Open findings']         = Open,
         ['Critical findings']     = Critical,
         ['Δ vs previous run (%)'] = DeltaPct
